const body = $json.body || {};
const query = $json.query || {};
const headers = $json.headers || {};

const base64 = body.fileData || body.csvBase64 || body.file || '';

if (!base64) {
  throw new Error('CSV source selected but no fileData found in request body. Expected body.fileData as base64 CSV content.');
}

return [
  {
    json: {
      ...$json,
      userEmail: body.userEmail || query.userEmail || headers['x-user-email'] || headers['X-User-Email'] || '',
      userName: body.userName || query.userName || 'Investor'
    },
    binary: {
      data: {
        data: base64,
        mimeType: 'text/csv',
        fileName: body.fileName || 'portfolio.csv'
      }
    }
  }
];

const allItems = $input.all();
let rows = [];

allItems.forEach(item => {
  const d = item.json;

  if (Array.isArray(d.data)) {
    rows = rows.concat(d.data);
  } else if (typeof d === 'object' && d.ticker) {
    rows.push(d);
  } else if (typeof d === 'object' && d !== null) {
    Object.keys(d).forEach(k => {
      if (Array.isArray(d[k])) rows = rows.concat(d[k]);
    });
  }
});

if (rows.length === 0) {
  rows = allItems.map(i => i.json);
}

const normalize = (v) => (v ?? '').toString().trim();

const holdings = rows.map(r => {
  const qty      = parseFloat(r.quantity) || 0;
  const avgBuy   = parseFloat(r.avg_buy_price) || 0;
  const curPrice = parseFloat(r.current_price) || 0;
  const marketVal = qty * curPrice;
  const costBasis = qty * avgBuy;
  const pnl       = marketVal - costBasis;
  const pnlPct    = costBasis > 0 ? ((pnl / costBasis) * 100) : 0;

  return {
    ticker: normalize(r.ticker || r.symbol || r.Ticker || r.Symbol) || 'UNKNOWN',
    company: normalize(r.company || r.Company || r.name || r.ticker) || 'UNKNOWN',
    sector: normalize(r.sector || r.Sector) || 'Unclassified',
    asset_class: normalize(r.asset_class || r.assetClass || r['asset class'] || r.AssetClass) || 'Equity',
    quantity: qty,
    avg_buy_price: avgBuy,
    current_price: curPrice,
    market_value: +marketVal.toFixed(2),
    cost_basis: +costBasis.toFixed(2),
    pnl: +pnl.toFixed(2),
    pnl_pct: +pnlPct.toFixed(2)
  };
}).filter(h => h.ticker !== 'UNKNOWN' && h.market_value > 0);

const totalValue  = holdings.reduce((s, h) => s + h.market_value, 0);
const totalCost   = holdings.reduce((s, h) => s + h.cost_basis, 0);
const totalPnl    = totalValue - totalCost;
const totalPnlPct = totalCost > 0 ? ((totalPnl / totalCost) * 100) : 0;

const holdingsWithAlloc = holdings.map(h => ({
  ...h,
  allocation_pct: totalValue > 0 ? +((h.market_value / totalValue) * 100).toFixed(2) : 0
}));

const sectorMap = {};
holdingsWithAlloc.forEach(h => {
  if (!sectorMap[h.sector]) sectorMap[h.sector] = { market_value: 0, holdings: [] };
  sectorMap[h.sector].market_value += h.market_value;
  sectorMap[h.sector].holdings.push(h.ticker);
});

const sectorBreakdown = Object.entries(sectorMap).map(([sector, data]) => ({
  sector,
  market_value: +data.market_value.toFixed(2),
  allocation_pct: totalValue > 0 ? +((data.market_value / totalValue) * 100).toFixed(2) : 0,
  tickers: data.holdings
})).sort((a, b) => b.allocation_pct - a.allocation_pct);

const acMap = {};
holdingsWithAlloc.forEach(h => {
  acMap[h.asset_class] = (acMap[h.asset_class] || 0) + h.market_value;
});

const assetClassBreakdown = Object.entries(acMap).map(([ac, val]) => ({
  asset_class: ac,
  market_value: +val.toFixed(2),
  allocation_pct: totalValue > 0 ? +((val / totalValue) * 100).toFixed(2) : 0
})).sort((a, b) => b.allocation_pct - a.allocation_pct);

const SINGLE_STOCK_THRESHOLD = 15;
const SECTOR_THRESHOLD = 35;
const TOP3_THRESHOLD = 60;

const overweightStocks = holdingsWithAlloc.filter(h => h.allocation_pct > SINGLE_STOCK_THRESHOLD);
const overweightSectors = sectorBreakdown.filter(s => s.allocation_pct > SECTOR_THRESHOLD);

const top3Value = [...holdingsWithAlloc]
  .sort((a, b) => b.market_value - a.market_value)
  .slice(0, 3)
  .reduce((s, h) => s + h.allocation_pct, 0);

const top3ConcentrationRisk = top3Value > TOP3_THRESHOLD;

let riskScore = 0;
riskScore += Math.min(overweightStocks.length * 10, 30);
riskScore += Math.min(overweightSectors.length * 15, 30);
riskScore += top3ConcentrationRisk ? 20 : 0;
riskScore += holdingsWithAlloc.length < 5 ? 20 : (holdingsWithAlloc.length < 10 ? 10 : 0);

const riskLabel = riskScore >= 60 ? 'HIGH' : riskScore >= 30 ? 'MEDIUM' : 'LOW';

const sortedByPnl = [...holdingsWithAlloc].sort((a, b) => b.pnl_pct - a.pnl_pct);
const topGainers = sortedByPnl.slice(0, 3);
const topLosers = sortedByPnl.slice(-3).reverse();

return [{
  json: {
    portfolio_summary: {
      total_market_value: +totalValue.toFixed(2),
      total_cost_basis: +totalCost.toFixed(2),
      total_pnl: +totalPnl.toFixed(2),
      total_pnl_pct: +totalPnlPct.toFixed(2),
      holding_count: holdingsWithAlloc.length,
      risk_score: riskScore,
      risk_label: riskLabel,
      analysis_timestamp: new Date().toISOString()
    },
    holdings: holdingsWithAlloc,
    sector_breakdown: sectorBreakdown,
    asset_class_breakdown: assetClassBreakdown,
    risk_flags: {
      overweight_stocks: overweightStocks.map(h => ({ ticker: h.ticker, allocation_pct: h.allocation_pct })),
      overweight_sectors: overweightSectors.map(s => ({ sector: s.sector, allocation_pct: s.allocation_pct })),
      top3_concentration_pct: +top3Value.toFixed(2),
      top3_concentration_risk: top3ConcentrationRisk,
      single_stock_threshold: SINGLE_STOCK_THRESHOLD,
      sector_threshold: SECTOR_THRESHOLD
    },
    top_gainers: topGainers.map(h => ({ ticker: h.ticker, pnl_pct: h.pnl_pct, pnl: h.pnl })),
    top_losers: topLosers.map(h => ({ ticker: h.ticker, pnl_pct: h.pnl_pct, pnl: h.pnl }))
  }
}];
